#include <stdio.h>
#include<string.h>

int main(int argc, char **argv)
{
	char s[15];int a=0;
	scanf("%s",s);
	int k=strlen(s);
	for(int i=0;i<k/2;i++)
	{
		if(s[i]!=s[k-i-1])
		a=a+1;
	}
	if(k%2!=0){
		if(a<=1)
		printf("YES\n");
	else
		printf("NO\n");
	}
	else{
	if(a==1)
			printf("YES\n");
	else
		printf("NO\n");	
	}
	return 0;
}

